-- 1. Tabela de Memória do Chat
CREATE TABLE IF NOT EXISTS sameka_chat_message (
    id SERIAL PRIMARY KEY,
    session_id TEXT NOT NULL,
    user_id UUID,
    message JSONB NOT NULL,
    created_at TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_chat_message_user_id ON sameka_chat_message (user_id);
CREATE INDEX IF NOT EXISTS idx_chat_message_session ON sameka_chat_message (session_id);

-- 2. Garante colunas adicionadas em migrations posteriores (idempotente)
ALTER TABLE sameka_chat_message ADD COLUMN IF NOT EXISTS user_id UUID;

-- Trigger que popula user_id em sameka_chat_message a partir do JWT da sessão.
-- A FUNÇÃO precisa existir (criada uma vez via SQL Editor do Supabase como owner — migration 007).
-- Aqui apenas re-anexamos o trigger de forma idempotente.
DO $$
BEGIN
  IF EXISTS (
    SELECT 1 FROM pg_proc WHERE proname = 'trg_set_chat_user_id'
  ) THEN
    EXECUTE 'DROP TRIGGER IF EXISTS trg_chat_set_user_id ON sameka_chat_message';
    EXECUTE 'CREATE TRIGGER trg_chat_set_user_id BEFORE INSERT ON sameka_chat_message FOR EACH ROW EXECUTE FUNCTION trg_set_chat_user_id()';
  END IF;
END $$;

-- Reaplica colunas adicionadas em migrations 002-006 de forma idempotente.
-- (Roles, company_name, coverage_areas, prevent self delete)

ALTER TABLE IF EXISTS sameka_user ADD COLUMN IF NOT EXISTS role TEXT DEFAULT 'viewer';
ALTER TABLE IF EXISTS sameka_user ADD COLUMN IF NOT EXISTS company_name TEXT;
ALTER TABLE IF EXISTS sameka_user ADD COLUMN IF NOT EXISTS coverage_areas JSONB DEFAULT '[]'::jsonb;

CREATE INDEX IF NOT EXISTS idx_sameka_user_role ON sameka_user (role);
